  1→// Core analysis engine — server-side.
  2→// Ported from web repo (src/lib/llm/analysis.ts) with SQLite persistence replacing Firestore.
  3→// Key differences from web repo:
  4→//   - Uses SQLiteMessageRow instead of web Message type
  5→//   - Writes insights directly to SQLite via getDb() (not Firestore)
  6→//   - Abort handling uses error.name === 'AbortError' (not DOMException)
  7→//   - Uses session's existing project_id from SQLite (not re-derived hash)
  8→
  9→import { randomUUID } from 'crypto';
 10→import { getDb } from '@code-insights/cli/db/client';
 11→import { createLLMClient, isLLMConfigured } from './client.js';
 12→import {
 13→  SESSION_ANALYSIS_SYSTEM_PROMPT,
 14→  generateSessionAnalysisPrompt,
 15→  formatMessagesForAnalysis,
 16→  parseAnalysisResponse,
 17→  PROMPT_QUALITY_SYSTEM_PROMPT,
 18→  generatePromptQualityPrompt,
 19→  parsePromptQualityResponse,
 20→  type SQLiteMessageRow,
 21→  type AnalysisResponse,
 22→  type PromptQualityResponse,
 23→  type ParseError,
 24→} from './prompts.js';
 25→
 26→// Re-export SQLiteMessageRow so routes can import it from analysis.ts directly
 27→export type { SQLiteMessageRow };
 28→
 29→// Maximum tokens to send to LLM (leaving room for response)
 30→const MAX_INPUT_TOKENS = 80000;
 31→const ANALYSIS_VERSION = '3.0.0';
 32→
 33→export interface AnalysisProgress {
 34→  phase: 'loading_messages' | 'analyzing' | 'saving';
 35→  currentChunk?: number;
 36→  totalChunks?: number;
 37→}
 38→
 39→export interface AnalysisOptions {
 40→  onProgress?: (progress: AnalysisProgress) => void;
 41→  signal?: AbortSignal;
 42→}
 43→
 44→export interface AnalysisResult {
 45→  success: boolean;
 46→  insights: InsightRow[];
 47→  error?: string;
 48→  error_type?: string;
 49→  response_length?: number;
 50→  response_preview?: string;
 51→  usage?: {
 52→    inputTokens: number;
 53→    outputTokens: number;
 54→  };
 55→}
 56→
 57→// Re-export ParseError so routes can import it from analysis.ts
 58→export type { ParseError };
