236→/**
237→ * Select the appropriate system prompt for the given format and scope.
238→ */
239→export function getExportSystemPrompt(ctx: ExportContext): string {
240→  const { format, scope, projectName = 'unknown', exportDate } = ctx;
241→
242→  switch (format) {
243→    case 'agent-rules':
244→      return scope === 'project'
245→        ? AGENT_RULES_PROJECT_SYSTEM_PROMPT(projectName)
246→        : AGENT_RULES_ALL_SYSTEM_PROMPT;
247→
248→    case 'knowledge-brief':
249→      return scope === 'project'
250→        ? KNOWLEDGE_BRIEF_PROJECT_SYSTEM_PROMPT(projectName)
251→        : KNOWLEDGE_BRIEF_ALL_SYSTEM_PROMPT;
252→
253→    case 'obsidian':
254→      return scope === 'project'
255→        ? OBSIDIAN_PROJECT_SYSTEM_PROMPT(projectName, exportDate)
256→        : OBSIDIAN_ALL_SYSTEM_PROMPT(exportDate);
257→
258→    case 'notion':
259→      return scope === 'project'
260→        ? NOTION_PROJECT_SYSTEM_PROMPT(projectName)
261→        : NOTION_ALL_SYSTEM_PROMPT;
262→
263→    default:
264→      return AGENT_RULES_PROJECT_SYSTEM_PROMPT(projectName);
265→  }
266→}
